   678→    // Evaluate with AI
   679→    const evaluation = await evaluateSkillAssessment(questions, responses, skillName, { subscriptionId });
   680→
   681→    // Update assessment record
   682→    await pool.query(`
   683→      UPDATE skill_assessments SET
   684→        responses = $2,
   685→        score = $3,
   686→        passed = $4,
   687→        ai_feedback = $5,
   688→        completed_at = NOW()
   689→      WHERE id = $1
   690→    `, [assessmentId, JSON.stringify(responses), evaluation.score, evaluation.passed, JSON.stringify(evaluation)]);
   691→
   692→    // If passed, verify the skill
   693→    if (evaluation.passed && assessment.rows[0].skill_id) {
   694→      await pool.query(`
   695→        UPDATE candidate_skills SET
   696→          is_verified = true,
   697→          verified_at = NOW(),
   698→          verified_score = $2,
   699→          level = GREATEST(level, $3)
   700→        WHERE id = $1
   701→      `, [assessment.rows[0].skill_id, evaluation.score, evaluation.recommended_level || 3]);
