        screening_answers = $7,
        updated_at = NOW()
      RETURNING *
    `, [req.user.id, req.params.jobId, job.rows[0].company_id, cover_letter, matchScore, omniscore, JSON.stringify(screening_answers || {})]);

    res.json({ success: true, application: result.rows[0] });
  } catch (err) {
