      SELECT DISTINCT ON (u.id)
        u.id, u.name, u.email
      FROM job_applications ja
      JOIN users u ON ja.candidate_id = u.id
      WHERE ja.company_id = $1
      ORDER BY u.id, ja.applied_at DESC
    `, [req.user.company_id]);

